evaluators.evaluation_logic:
const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const categories = JSON.parse(localStorage.getItem('product_categories') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

// Identify Square Tubes category if available
const squareCat = categories.find(c => c.slug === 'square-tubes' || c.name === 'Square Tubes');
const squareCatId = squareCat ? squareCat.id : null;

// Find all qualifying stainless steel 2x2x6 ft square tubes under $80
const candidates = products.filter(p => {
  if (!p || p.status !== 'active') return false;
  if (p.material !== 'stainless_steel') return false;
  if (p.profile_type !== 'square_tube') return false;
  if (squareCatId && p.category_id !== squareCatId) return false;
  if (typeof p.unit_price !== 'number' || p.unit_price >= 80) return false;
  if (typeof p.size_label !== 'string') return false;
  const label = p.size_label.toLowerCase();
  return label.includes('2 in x 2 in x 6 ft');
});

let qtyCheapest = 0;
if (candidates.length > 0 && carts.length > 0 && Array.isArray(cartItems)) {
  // Determine cheapest qualifying product by unit price
  candidates.sort((a, b) => (a.unit_price || 0) - (b.unit_price || 0));
  const cheapest = candidates[0];

  const activeCart = carts[carts.length - 1];
  const itemsForCart = cartItems.filter(ci => ci.cart_id === activeCart.id && ci.product_id === cheapest.id);
  qtyCheapest = itemsForCart.reduce((sum, ci) => sum + (ci.quantity || 0), 0);
}

// CP1 (0.30): User added the cheapest qualifying tube to the active cart (any quantity > 0)
checkpoints.push({ passed: qtyCheapest >= 1, weight: 0.30 });
// CP2 (0.70): User has at least 6 units of the cheapest qualifying tube in the active cart
checkpoints.push({ passed: qtyCheapest >= 6, weight: 0.70 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const requests = JSON.parse(localStorage.getItem('laser_cutting_quote_requests') || '[]');

// Tier 1: Correct service, material, and plate dimensions in mm
const tier1 = requests.filter(r => {
  if (!r || r.service_id !== 'laser_cutting') return false;
  if (r.material !== 'steel') return false;
  if (r.thickness_unit !== 'mm' || r.length_unit !== 'mm' || r.width_unit !== 'mm') return false;
  if (typeof r.thickness_value !== 'number' || typeof r.length_value !== 'number' || typeof r.width_value !== 'number') return false;
  const thicknessOk = Math.abs(r.thickness_value - 10) < 0.001;
  const lengthOk = Math.abs(r.length_value - 1000) < 0.001;
  const widthOk = Math.abs(r.width_value - 500) < 0.001;
  return thicknessOk && lengthOk && widthOk;
});

// Tier 2: Also correct quantity (>=15)
const tier2 = tier1.filter(r => typeof r.quantity === 'number' && r.quantity >= 15);

// Tier 3: Also correct tolerance (±0.5 mm) and shipping ZIP 94105
const tier3 = tier2.filter(r => {
  if (r.shipping_zip !== '94105') return false;
  if (r.tolerance_type !== 'plus_minus') return false;
  if (r.tolerance_unit !== 'mm') return false;
  if (typeof r.tolerance_value !== 'number') return false;
  return Math.abs(r.tolerance_value - 0.5) < 0.001;
});

// CP1 (0.30): At least one request with correct material and dimensions in mm
checkpoints.push({ passed: tier1.length > 0, weight: 0.30 });
// CP2 (0.30): At least one such request also has quantity >= 15
checkpoints.push({ passed: tier2.length > 0, weight: 0.30 });
// CP3 (0.40): At least one such request also has ZIP 94105 and ±0.5 mm tolerance
checkpoints.push({ passed: tier3.length > 0, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

// All qualifying galvanized handrail kits for about 3 steps with free shipping and price < $250
const candidates = products.filter(p => {
  if (!p || p.status !== 'active') return false;
  if (p.material !== 'galvanized_steel') return false;
  if (p.profile_type !== 'handrail_kit') return false;
  if (typeof p.application_min_steps !== 'number' || typeof p.application_max_steps !== 'number') return false;
  // "about 3 steps": range must include 3
  if (!(p.application_min_steps <= 3 && p.application_max_steps >= 3)) return false;
  if (!p.free_shipping) return false;
  if (typeof p.unit_price !== 'number' || p.unit_price >= 250) return false;
  return true;
});

let qualifyingInCartCount = 0;
let cheapestInCartCount = 0;

if (candidates.length > 0 && carts.length > 0 && Array.isArray(cartItems)) {
  const activeCart = carts[carts.length - 1];
  const itemsForCart = cartItems.filter(ci => ci.cart_id === activeCart.id);

  // Any qualifying handrail kit in cart (correct type, not necessarily cheapest yet)
  qualifyingInCartCount = itemsForCart.filter(ci => {
    if (!ci || !ci.product_id || (ci.quantity || 0) <= 0) return false;
    return candidates.some(p => p.id === ci.product_id && (ci.quantity || 0) >= 1);
  }).length;

  // Determine cheapest price among candidates
  candidates.sort((a, b) => (a.unit_price || 0) - (b.unit_price || 0));
  const cheapestPrice = candidates[0].unit_price;
  const cheapestIds = candidates.filter(p => p.unit_price === cheapestPrice).map(p => p.id);

  cheapestInCartCount = itemsForCart.filter(ci => {
    if (!ci || !ci.product_id || (ci.quantity || 0) <= 0) return false;
    return cheapestIds.includes(ci.product_id) && (ci.quantity || 0) >= 1;
  }).length;
}

// CP1 (0.40): Cart has at least one qualifying galvanized handrail kit for ~3 steps with free shipping and < $250
checkpoints.push({ passed: qualifyingInCartCount > 0, weight: 0.40 });
// CP2 (0.60): Cart includes at least one unit of the cheapest qualifying handrail kit
checkpoints.push({ passed: cheapestInCartCount > 0, weight: 0.60 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const requests = JSON.parse(localStorage.getItem('factory_tour_requests') || '[]');

const now = new Date();
const nextMonthStart = new Date(now.getFullYear(), now.getMonth() + 1, 1);
const followingMonthStart = new Date(now.getFullYear(), now.getMonth() + 2, 1);

// Tier 1: Correct group size and time (10:00 AM)
const tier1 = requests.filter(r => {
  if (!r) return false;
  if (r.group_size !== 4) return false;
  if (typeof r.preferred_time !== 'string') return false;
  return r.preferred_time.trim().toLowerCase() === '10:00 am';
});

// Tier 2: Also date within next calendar month
const tier2 = tier1.filter(r => {
  const d = new Date(r.preferred_date);
  if (isNaN(d.getTime())) return false;
  return d >= nextMonthStart && d < followingMonthStart;
});

// Tier 3: Also on a weekday (Mon-Fri)
const tier3 = tier2.filter(r => {
  const d = new Date(r.preferred_date);
  if (isNaN(d.getTime())) return false;
  const day = d.getDay(); // 0=Sun,6=Sat
  return day !== 0 && day !== 6;
});

// CP1 (0.30): Request with group_size=4 and preferred_time='10:00 AM'
checkpoints.push({ passed: tier1.length > 0, weight: 0.30 });
// CP2 (0.30): Such a request scheduled within the next calendar month
checkpoints.push({ passed: tier2.length > 0, weight: 0.30 });
// CP3 (0.40): Such a request is also on a weekday
checkpoints.push({ passed: tier3.length > 0, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const wishlistItems = JSON.parse(localStorage.getItem('wishlist_items') || '[]');
// Instrumentation variable: productId whose datasheet link was clicked
const downloadedId = localStorage.getItem('task5_datasheetDownloadedProductId');

// All HEA 200 beam products
const hea200Products = products.filter(p => {
  if (!p || p.status !== 'active') return false;
  if (p.profile_type !== 'hea_beam') return false;
  if (typeof p.size_label !== 'string') return false;
  return p.size_label.toLowerCase().includes('hea 200');
});

// Datasheet download correctness
const downloadedHeaProduct = hea200Products.find(p => {
  if (!downloadedId) return false;
  if (p.id !== downloadedId) return false;
  return typeof p.datasheet_url === 'string' && p.datasheet_url.length > 0;
});

// Wishlist items that are HEA 200 beams
const wishlistHeaItems = wishlistItems.filter(wi => {
  if (!wi || !wi.product_id) return false;
  return hea200Products.some(p => p.id === wi.product_id);
});

// Same product both downloaded and saved
const sameProductBoth = wishlistHeaItems.some(wi => wi.product_id === downloadedId);

// CP1 (0.30): User downloaded the datasheet of an HEA 200 beam product
checkpoints.push({ passed: !!downloadedHeaProduct, weight: 0.30 });
// CP2 (0.30): User saved at least one HEA 200 beam product to any wishlist
checkpoints.push({ passed: wishlistHeaItems.length > 0, weight: 0.30 });
// CP3 (0.40): The downloaded HEA 200 product is the same one saved to a wishlist
checkpoints.push({ passed: sameProductBoth, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const configured = JSON.parse(localStorage.getItem('configured_products') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

// Base configurable cabinet products
const baseCabinets = products.filter(p => p && p.status === 'active' && p.profile_type === 'cabinet' && p.is_configurable);

// Configurations that meet the task criteria
const qualifyingConfigs = configured.filter(cp => {
  if (!cp || cp.configuration_type !== 'cabinet') return false;
  if (!baseCabinets.some(b => b.id === cp.base_product_id)) return false;

  if (typeof cp.height_value !== 'number' || typeof cp.width_value !== 'number' || typeof cp.depth_value !== 'number') return false;
  // Height about 2000 mm (between 1900 and 2100)
  if (!(cp.height_value >= 1900 && cp.height_value <= 2100)) return false;
  // Width at least 900 mm
  if (cp.width_value < 900) return false;
  // Depth between 450 and 500 mm
  if (!(cp.depth_value >= 450 && cp.depth_value <= 500)) return false;

  // Color RAL 7035
  if (!cp.color_code || cp.color_code.toUpperCase().indexOf('RAL 7035') === -1) return false;

  // Exactly 4 shelves
  if (cp.shelves_count !== 4) return false;

  // Lockable door
  if (!cp.has_lockable_door) return false;

  // Price under $600
  if (typeof cp.unit_price !== 'number' || cp.unit_price >= 600) return false;

  return true;
});

let configsWithQty2 = [];
if (qualifyingConfigs.length > 0 && carts.length > 0 && Array.isArray(cartItems)) {
  const activeCart = carts[carts.length - 1];
  const itemsForCart = cartItems.filter(ci => ci.cart_id === activeCart.id);

  configsWithQty2 = qualifyingConfigs.filter(cp => {
    const totalQty = itemsForCart
      .filter(ci => ci.configured_product_id === cp.id)
      .reduce((sum, ci) => sum + (ci.quantity || 0), 0);
    return totalQty >= 2;
  });
}

// CP1 (0.40): At least one configured cabinet meets all configuration criteria
checkpoints.push({ passed: qualifyingConfigs.length > 0, weight: 0.40 });
// CP2 (0.60): Such a qualifying configured cabinet has quantity >= 2 in the active cart
checkpoints.push({ passed: configsWithQty2.length > 0, weight: 0.60 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const requests = JSON.parse(localStorage.getItem('emergency_repair_requests') || '[]');

// Requests for emergency repair in Midwest within 24 hours
const midwest24 = requests.filter(r => {
  if (!r) return false;
  if (r.service_id !== 'emergency_repair') return false;
  if (r.region !== 'midwest') return false;
  if (r.priority !== 'within_24_hours') return false;
  return true;
});

// Among those, require non-empty issue description, site address, and contact details
const withFullDetails = midwest24.filter(r => {
  const nonEmpty = v => typeof v === 'string' && v.trim().length > 0;
  if (!nonEmpty(r.issue_description)) return false;
  if (!nonEmpty(r.site_street)) return false;
  if (!nonEmpty(r.site_city)) return false;
  if (!nonEmpty(r.site_zip)) return false;
  if (!nonEmpty(r.contact_name)) return false;
  if (!nonEmpty(r.contact_email)) return false;
  if (!nonEmpty(r.contact_phone)) return false;
  return true;
});

// CP1 (0.40): At least one emergency repair request for Midwest with priority within 24 hours
checkpoints.push({ passed: midwest24.length > 0, weight: 0.40 });
// CP2 (0.60): Such a request includes full issue description, site address, and contact details
checkpoints.push({ passed: withFullDetails.length > 0, weight: 0.60 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const shippingMethods = JSON.parse(localStorage.getItem('shipping_methods') || '[]');
const sessions = JSON.parse(localStorage.getItem('checkout_sessions') || '[]');

// Identify candidate products by dynamic criteria
const aluminumSheets = products.filter(p => {
  if (!p || p.status !== 'active') return false;
  if (p.material !== 'aluminum') return false;
  if (p.profile_type !== 'sheet') return false;
  if (p.thickness_unit !== 'mm' || typeof p.thickness_value !== 'number') return false;
  return Math.abs(p.thickness_value - 3) < 0.001;
});

const steelAngles = products.filter(p => {
  if (!p || p.status !== 'active') return false;
  if (p.material !== 'steel') return false;
  if (p.profile_type !== 'angle') return false;
  if (p.length_unit !== 'm' || typeof p.length_value !== 'number') return false;
  return Math.abs(p.length_value - 1) < 0.001;
});

const stainlessBolts = products.filter(p => {
  if (!p || p.status !== 'active') return false;
  if (p.material !== 'stainless_steel') return false;
  if (p.profile_type !== 'bolt') return false;
  return true;
});

let mixCorrect = false;
let shippingCorrect = false;

if (carts.length > 0 && Array.isArray(cartItems)) {
  const activeCart = carts[carts.length - 1];
  const itemsForCart = cartItems.filter(ci => ci.cart_id === activeCart.id);

  const aluIds = new Set(aluminumSheets.map(p => p.id));
  const angleIds = new Set(steelAngles.map(p => p.id));
  const boltIds = new Set(stainlessBolts.map(p => p.id));

  let qtyAlu = 0;
  let qtyAngle = 0;
  let qtyBolt = 0;

  itemsForCart.forEach(ci => {
    const pid = ci.product_id;
    const qty = ci.quantity || 0;
    if (!pid || qty <= 0) return;
    if (aluIds.has(pid)) qtyAlu += qty;
    if (angleIds.has(pid)) qtyAngle += qty;
    if (boltIds.has(pid)) qtyBolt += qty;
  });

  // Require at least 1 aluminum sheet, 2 steel angles, 4 stainless bolts
  mixCorrect = qtyAlu >= 1 && qtyAngle >= 2 && qtyBolt >= 4;

  // Determine checkout session for this cart
  const cartSessions = sessions.filter(s => s && s.cart_id === activeCart.id);
  let session = null;
  if (cartSessions.length > 0) {
    cartSessions.sort((a, b) => {
      const ta = new Date(a.created_at || 0).getTime();
      const tb = new Date(b.created_at || 0).getTime();
      return ta - tb;
    });
    session = cartSessions[cartSessions.length - 1];
  }

  if (session && session.selected_shipping_method_id) {
    const selected = shippingMethods.find(m => m.id === session.selected_shipping_method_id);

    // Shipping methods that promise delivery within 5 days (max_delivery_days <= 5)
    const fastMethods = shippingMethods.filter(m => typeof m.max_delivery_days === 'number' && m.max_delivery_days <= 5);

    if (selected && fastMethods.length > 0 && fastMethods.some(m => m.id === selected.id)) {
      const minPrice = fastMethods.reduce((min, m) => {
        const price = typeof m.price === 'number' ? m.price : Infinity;
        return price < min ? price : min;
      }, Infinity);
      const cheapestFast = fastMethods.filter(m => m.price === minPrice).map(m => m.id);
      shippingCorrect = cheapestFast.includes(selected.id);
    }
  }
}

// CP1 (0.30): Cart contains the correct mix of qualifying aluminum sheet, steel angles, and stainless bolts
checkpoints.push({ passed: mixCorrect, weight: 0.30 });
// CP2 (0.70): Selected shipping method is the cheapest option with max_delivery_days <= 5 for the active cart
checkpoints.push({ passed: shippingCorrect, weight: 0.70 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
